#[derive(Debug, thiserror::Error)]
pub enum ClarifyAsProjectError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to clarify this inbox item")]
    Unauthorized,
    #[error("Invalid first action title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

pub struct ClarifyAsProjectResult {
    pub project: Project,
    pub first_action: NextAction,
}

#[tracing::instrument(
    name = "clarify_as_project",
    skip(pool, first_action_title),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn clarify_as_project(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
    context_id: ContextId,
    first_action_title: String,
) -> Result<ClarifyAsProjectResult, ClarifyAsProjectError> {
    let first_action_title = TodoTitle::parse(first_action_title)?;

    let mut tx = pool.begin().await.map_err(|e| {
        ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to begin transaction: {e}"))
    })?;

    let item = inbox_repository::find_inbox_item_by_id(&mut *tx, item_id)
        .await
        .map_err(|e| ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(ClarifyAsProjectError::NotFound)?;

    if item.user_id() != user_id {
        return Err(ClarifyAsProjectError::Unauthorized);
    }

    let project = Project::new(user_id.clone(), item.title().clone());

    project_repository::insert_project(&mut *tx, &project)
        .await
        .map_err(|e| {
            ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to insert project: {e}"))
        })?;

    let first_action = NextAction::new_for_project(
        user_id.clone(),
        context_id,
        project.id().clone(),
        first_action_title,
    );

    next_action_repository::insert_next_action(&mut *tx, &first_action)
        .await
        .map_err(|e| {
            ClarifyAsProjectError::Unexpected(anyhow::anyhow!(
                "Failed to insert first next action: {e}"
            ))
        })?;

    inbox_repository::delete_inbox_item(&mut *tx, item_id)
        .await
        .map_err(|e| {
            ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to delete inbox item: {e}"))
        })?;

    tx.commit().await.map_err(|e| {
        ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to commit transaction: {e}"))
    })?;

    tracing::info!("Inbox item clarified as project");
    Ok(ClarifyAsProjectResult {
        project,
        first_action,
    })
}

#[derive(serde::Deserialize)]
pub struct ClarifyForm {
    pub context_id: Uuid,
    #[serde(default)]
    pub clarify_type: String,
    #[serde(default)]
    pub first_action_title: String,
}

pub async fn post_clarify_inbox_item(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(item_id): Path<Uuid>,
    Form(form): Form<ClarifyForm>,
) -> Result<Response, InboxError> {
    let htmx = is_htmx_request(&headers);
    let inbox_item_id = InboxItemId::from_uuid(item_id);
    let context_id = ContextId::from_uuid(form.context_id);

    if form.clarify_type == "project" {
        match clarify_as_project(
            &pool,
            &inbox_item_id,
            &user_id,
            context_id,
            form.first_action_title,
        )
        .await
        {
            Ok(_result) => {
                if htmx {
                    Ok(htmx_response_with_announce(
                        Html(String::new()),
                        "Clarified as project",
                    ))
                } else {
                    Ok(Redirect::to("/inbox").into_response())
                }
            }
            Err(ClarifyAsProjectError::NotFound) => Ok((
                StatusCode::NOT_FOUND,
                Html("<h1>Inbox item not found</h1>".to_string()),
            )
                .into_response()),
            Err(ClarifyAsProjectError::Unauthorized) => Ok((
                StatusCode::FORBIDDEN,
                Html("<h1>Not authorized</h1>".to_string()),
            )
                .into_response()),
            Err(ClarifyAsProjectError::InvalidTitle(_)) => Ok((
                StatusCode::UNPROCESSABLE_ENTITY,
                Html("<h1>First action title is required for projects</h1>".to_string()),
            )
                .into_response()),
            Err(ClarifyAsProjectError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
        }
    } else {
        match clarify_as_next_action(&pool, &inbox_item_id, &user_id, context_id).await {
            Ok(_action) => {
                if htmx {
                    Ok(htmx_response_with_announce(
                        Html(String::new()),
                        "Clarified as next action",
                    ))
                } else {
                    Ok(Redirect::to("/inbox").into_response())
                }
            }
            Err(ClarifyAsNextActionError::NotFound) => Ok((
                StatusCode::NOT_FOUND,
                Html("<h1>Inbox item not found</h1>".to_string()),
            )
                .into_response()),
            Err(ClarifyAsNextActionError::Unauthorized) => Ok((
                StatusCode::FORBIDDEN,
                Html("<h1>Not authorized</h1>".to_string()),
            )
                .into_response()),
            Err(ClarifyAsNextActionError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
        }
    }
}

